const __pageData = JSON.parse('{"title":"数据流与认知轨迹","description":"从认知科学视角深度剖析Redux、MobX、Zustand、Signals四种状态管理模式的认知负荷差异，建立数据流架构与人类心智模型之间的严格映射关系","frontmatter":{"title":"数据流与认知轨迹","description":"从认知科学视角深度剖析Redux、MobX、Zustand、Signals四种状态管理模式的认知负荷差异，建立数据流架构与人类心智模型之间的严格映射关系","date":"2026-05-01T00:00:00.000Z","tags":["理论前沿","认知科学","状态管理","数据流","心智模型"],"category":"theoretical-foundations"},"headers":[],"relativePath":"theoretical-foundations/cog-09-data-flow.md","filePath":"theoretical-foundations/cog-09-data-flow.md","lastUpdated":1777743710000}');
